+    private static void rewriteServletReferences(CtModel model) {
+        List<CtTypeReference<?>> typeReferences = new ArrayList<>(
+                model.getElements(new TypeFilter<>(CtTypeReference.class)));
+        for (CtTypeReference<?> reference : typeReferences) {
+            rewriteTypeReference(reference);
+        }
+
+        List<CtImport> imports = new ArrayList<>(model.getElements(new TypeFilter<>(CtImport.class)));
+        for (CtImport ctImport : imports) {
