+        CtElement parent = reference.getParent();
+        if (parent == null) {
+            return;
+        }
+
+        String rewritten = qualifiedName.replaceFirst("^javax\\.servlet", NEW_PREFIX);
+        CtTypeReference<?> replacement = reference.getFactory().Type().createReference(rewritten);
+        reference.replace(replacement);
+    }
+}
